codeCreate.query:
#graphql
  mutation DiscountCodeFreeShippingLifecycleCreate($input: DiscountCodeFreeShippingInput!) {
    discountCodeFreeShippingCreate(freeShippingCodeDiscount: $input) {
      #graphql
  codeDiscountNode {
    id
    codeDiscount {
      __typename
      ... on DiscountCodeFreeShipping {
        title
        status
        summary
        startsAt
        endsAt
        createdAt
        updatedAt
        asyncUsageCount
        discountClasses
        combinesWith {
          productDiscounts
          orderDiscounts
          shippingDiscounts
        }
        codes(first: 2) {
          nodes {
            id
            code
            asyncUsageCount
          }
          pageInfo {
            hasNextPage
            hasPreviousPage
            startCursor
            endCursor
          }
        }
        context {
          __typename
          ... on DiscountBuyerSelectionAll {
            all
          }
        }
        minimumRequirement {
          __typename
          ... on DiscountMinimumSubtotal {
            greaterThanOrEqualToSubtotal {
              amount
              currencyCode
            }
          }
          ... on DiscountMinimumQuantity {
            greaterThanOrEqualToQuantity
          }
        }
        destinationSelection {
          __typename
          ... on DiscountCountryAll {
            allCountries
          }
          ... on DiscountCountries {
            countries
            includeRestOfWorld
          }
        }
        maximumShippingPrice {
          amount
          currencyCode
        }
        appliesOncePerCustomer
        appliesOnOneTimePurchase
        appliesOnSubscription
        recurringCycleLimit
        usageLimit
      }
    }
  }
  userErrors {
    field
    message
    code
    extraInfo
  }

    }
  }

