read.query:
#graphql
  query DiscountFreeShippingLifecycleRead($codeId: ID!, $automaticId: ID!, $code: String!) {
    discountNode(id: $codeId) {
      id
      discount {
        __typename
        ... on DiscountCodeFreeShipping {
          title
          status
        }
      }
    }
    codeDiscountNodeByCode(code: $code) {
      id
    }
    automaticDiscountNode(id: $automaticId) {
      id
      automaticDiscount {
        __typename
        ... on DiscountAutomaticFreeShipping {
          title
          status
        }
      }
    }
    discountNodes(first: 5, query: "type:free_shipping") {
      nodes {
        id
      }
    }
    discountNodesCount(query: "type:free_shipping") {
      count
      precision
    }
  }

upstreamCalls.query:
#graphql
  query DiscountHydrate($id: ID!) {
    codeNode: codeDiscountNode(id: $id) {
      id
      codeDiscount {
        __typename
        ... on DiscountCodeBasic {
          title
          status
          startsAt
          endsAt
          updatedAt
          asyncUsageCount
          codes(first: 250) {
            nodes {
              id
              code
              asyncUsageCount
            }
          }
        }
        ... on DiscountCodeApp {
          title
          status
          startsAt
          endsAt
          updatedAt
          asyncUsageCount
        }
        ... on DiscountCodeBxgy {
          title
          status
          startsAt
          endsAt
          updatedAt
          asyncUsageCount
        }
        ... on DiscountCodeFreeShipping {
          title
          status
          startsAt
          endsAt
          updatedAt
          asyncUsageCount
          codes(first: 250) {
            nodes {
              id
              code
              asyncUsageCount
            }
          }
          appliesOnOneTimePurchase
          appliesOnSubscription
        }
      }
    }
    automaticNode: automaticDiscountNode(id: $id) {
      id
      automaticDiscount {
        __typename
        ... on DiscountAutomaticBasic {
          title
          status
          startsAt
          endsAt
          updatedAt
          asyncUsageCount
        }
        ... on DiscountAutomaticApp {
          title
          status
          startsAt
          endsAt
          updatedAt
          asyncUsageCount
        }
        ... on DiscountAutomaticBxgy {
          title
          status
          startsAt
          endsAt
          updatedAt
          asyncUsageCount
        }
        ... on DiscountAutomaticFreeShipping {
          title
          status
          startsAt
          endsAt
          updatedAt
          asyncUsageCount
          appliesOnOneTimePurchase
          appliesOnSubscription
        }
      }
    }
